const WEBP=/\.(jpe?g|png)$/i,lazySel='img.lazy-image[data-src],img.lazy-image[data-srcset]',checked=new Map();let obs;function webpPath(s){return s&&WEBP.test(s)?s.replace(WEBP,'.webp'):''}async function hasFile(u){if(!u)return!1;if(checked.has(u))return checked.get(u);const p=fetch(u,{method:'HEAD'}).then(r=>r.ok).catch(()=>!1);checked.set(u,p);return p}function markCritical(i){if(i.dataset.critical!==undefined)return!0;if(i.getAttribute('fetchpriority')==='high')return!0;return!!i.closest('.header-logo,.hero-banner,.brand-media,.project-main-card,.product-gallery,.product-main')}function reveal(i){if(i.dataset.loading==='done')return;i.dataset.loading='done';const ds=i.dataset.src,ss=i.dataset.srcset;if(ds){i.src=ds;delete i.dataset.src}if(ss){i.srcset=ss;delete i.dataset.srcset}const s=i.parentElement?.querySelector('source[data-srcset]');if(s){s.srcset=s.dataset.srcset;delete s.dataset.srcset}}async function toPicture(i){if(i.closest('picture')||i.dataset.webpApplied==='1')return;i.dataset.webpApplied='1';const src=i.getAttribute('src');const wp=webpPath(src);if(!wp||!(await hasFile(wp)))return;const p=document.createElement('picture'),s=document.createElement('source');if(i.dataset.src){s.dataset.srcset=wp}else s.srcset=wp;s.type='image/webp';i.parentNode.insertBefore(p,i);p.appendChild(s);p.appendChild(i)}async function prep(i){if(!i||i.dataset.perf==='1'||!i.getAttribute('src'))return;i.dataset.perf='1';await toPicture(i);if(markCritical(i)){i.classList.add('lazy-loaded');return}if(i.dataset.src||i.loading==='eager')return;i.dataset.src=i.getAttribute('src');i.removeAttribute('src');i.classList.add('lazy-image');if(i.complete){i.classList.add('lazy-loaded')}else i.addEventListener('load',()=>i.classList.add('lazy-loaded'),{once:!0})}function initObs(){if('IntersectionObserver'in window){obs=new IntersectionObserver((es,o)=>{es.forEach(e=>{if(!e.isIntersecting)return;reveal(e.target);o.unobserve(e.target)})},{rootMargin:'300px 0px',threshold:.01});document.querySelectorAll(lazySel).forEach(i=>obs.observe(i));return}document.querySelectorAll(lazySel).forEach(i=>reveal(i))}function preload(){const imgs=[...document.querySelectorAll('img')].filter(markCritical).slice(0,3);imgs.forEach(i=>{const href=i.dataset.src||i.getAttribute('src');if(!href||document.head.querySelector(`link[rel="preload"][href="${href}"]`))return;const l=document.createElement('link');l.rel='preload';l.as='image';l.href=href;document.head.appendChild(l)})}function process(root=document){root.querySelectorAll('img[src]').forEach(prep);if(obs)root.querySelectorAll(lazySel).forEach(i=>obs.observe(i))}document.addEventListener('DOMContentLoaded',()=>{process();initObs();preload();const m=new MutationObserver(ms=>{ms.forEach(x=>x.addedNodes.forEach(n=>{if(n.nodeType!==1)return;if(n.matches?.('img[src]'))prep(n);process(n)}))});m.observe(document.body,{childList:!0,subtree:!0})});
